/**
 * Sourced from the broker (action get_capabilities, source capability_probe) so the UI can pre-emptively label which reports/views are available. Falls back to the CAPABILITIES env override, or demo defaults.
 * @summary Which data domains the wired backend(s) can populate
 */
export const GetCapabilitiesResponse = zod.object({
  "mode": zod.string().describe('How capabilities were resolved (broker | env | demo).'),
  "issues": zod.boolean(),
  "scheduling": zod.boolean(),
  "resources": zod.boolean(),
  "financials": zod.boolean(),
  "portfolio": zod.boolean(),
  "baseline": zod.boolean(),
  "blockers": zod.boolean(),
  "history": zod.boolean(),
  "raid": zod.boolean(),
  "quality": zod.boolean().describe('Risk & quality fields (health\/RAG, impact, urgency, blocked).'),
  "crm": zod.boolean().describe('CRM\/sales fields (deal value, probability, forecast).'),
  "service": zod.boolean().describe('ITSM\/service fields (SLA, CSAT, change management).'),
  "benefits": zod.boolean().describe('Benefits-realisation fields (planned vs actual benefit value, measure, owner, status) — true only when a backend can carry them.'),
  "timeTravel": zod.boolean().describe('Whether historical time-travel is available — true only when the operator has opted in to the logging-server egress (off by default).'),
  "fields": zod.record(zod.string(), zod.object({
  "surface": zod.boolean(),
  "store": zod.boolean()
}).describe('Whether a field\/entity can be surfaced (read) and stored (written).')).optional().describe('Per-field support: which work-item fields the backend can surface (read\/display) and store (write back). Absent ⇒ derive from domains.'),
  "entities": zod.record(zod.string(), zod.object({
  "surface": zod.boolean(),
  "store": zod.boolean()
}).describe('Whether a field\/entity can be surfaced (read) and stored (written).')).optional().describe('Per-entity support (e.g. programme, project): whether the entity can be surfaced and\/or stored. A programme only exists when the backend can carry programme grouping.'),
  "customFields": zod.array(zod.object({
  "key": zod.string(),
  "label": zod.string().optional(),
  "type": zod.string().optional(),
  "surface": zod.boolean().optional(),
  "store": zod.boolean().optional(),
  "references": zod.string().optional(),
  "sourceSystem": zod.string().optional().describe('System of record this field is read from (e.g. \"jira\").'),
  "sourceField": zod.string().optional().describe('The backend\'s native field name\/id this field maps from.')
}).describe('A field a backend\'s describe reported, with its metadata preserved.')).optional().describe('Non-canonical fields the backend\'s describe surfaced (the reconcile path): tenant\/custom fields the registry doesn\'t model, carried through as gated passthrough so they light up without a registry edit.'),
  "fieldSources": zod.record(zod.string(), zod.object({
  "system": zod.string(),
  "field": zod.string()
}).describe('Where a canonical\/custom field is read from (system + native field).')).optional().describe('Per-field lineage: which backend system + native field each canonical or custom field is read from (e.g. dueDate → jira:duedate). Absent when the broker doesn\'t declare it.')
}).describe('Data domains the wired backend(s) can populate.')


/**
 * A bounded, in-memory ring of the most recent gateway → broker → backend actions (action, result, status, latency, actor), so an admin can watch traffic and surface failures live. Pair with the SSE stream at /admin/broker-log/stream for live tailing. Requires the admin role.
 * @summary Recent brokered actions (admin-only live log)
 */
export const GetBrokerLogResponseItem = zod.object({
  "ts": zod.string(),
  "action": zod.string(),
  "result": zod.enum(['success', 'error']),
  "status": zod.number(),
  "ms": zod.number(),
  "projectId": zod.string().nullish(),
  "actor": zod.string().nullish(),
  "note": zod.string().nullish()
}).describe('One brokered action in the admin live log (redacted projection).')
export const GetBrokerLogResponse = zod.array(GetBrokerLogResponseItem)


/**
 * Enumerates the fields the active backend exposes and reconciles them against the canonical registry (known / unknown / missing), flagging relationship candidates among the unknowns. Powers the admin translation layer's "what does this backend expose, what's unmapped" view. Requires the manager role (it reveals backend schema detail).
 * @summary Per-backend field manifest (the describe → reconcile path)
 */
export const GetFieldManifestResponse = zod.object({
  "mode": zod.string(),
  "enumerated": zod.array(zod.object({
  "key": zod.string(),
  "label": zod.string().optional(),
  "type": zod.string().optional(),
  "surface": zod.boolean().optional(),
  "store": zod.boolean().optional(),
  "references": zod.string().optional(),
  "sourceSystem": zod.string().optional().describe('System of record this field is read from (e.g. \"jira\").'),
  "sourceField": zod.string().optional().describe('The backend\'s native field name\/id this field maps from.')
}).describe('A field a backend\'s describe reported, with its metadata preserved.')),
  "reconciliation": zod.object({
  "known": zod.array(zod.string()),
  "unknown": zod.array(zod.string()),
  "missing": zod.array(zod.string())
}).describe('known\/unknown\/missing field keys vs the canonical registry.'),
  "customFields": zod.array(zod.object({
  "key": zod.string(),
  "label": zod.string().optional(),
  "type": zod.string().optional(),
  "surface": zod.boolean().optional(),
  "store": zod.boolean().optional(),
  "references": zod.string().optional(),
  "sourceSystem": zod.string().optional().describe('System of record this field is read from (e.g. \"jira\").'),
  "sourceField": zod.string().optional().describe('The backend\'s native field name\/id this field maps from.')
}).describe('A field a backend\'s describe reported, with its metadata preserved.')),
  "relationshipCandidates": zod.array(zod.object({
  "field": zod.string(),
  "references": zod.string(),
  "kind": zod.string()
}))
}).describe('The per-backend field manifest — the reconcile path made inspectable. Diffs the backend\'s describe against the canonical registry.')


/**
 * @summary Get integration settings
 */
export const GetSettingsResponse = zod.object({
  "brokerUrl": zod.string().nullish().describe('The active broker\'s webhook\/endpoint URL.'),
  "aiProvider": zod.enum(['none', 'openai', 'ollama', 'anthropic', 'openrouter']),
  "sttProvider": zod.enum(['none', 'browser', 'whisper']).optional().describe('Speech-to-text engine. \"browser\" runs on-device (no audio egress); \"whisper\" is an AI-assisted, off-device transcription provider (governance-gated). \"none\" disables dictation server-side.'),
  "aiModel": zod.string().nullish(),
  "backendSource": zod.string().describe('Free-form backend routing hint passed to the broker (e.g. \"all\", \"jira\", \"azure-devops\", \"servicenow\", \"plane\", \"openproject\"). \"all\" means no filter — whatever the broker is wired to.'),
  "reportingCurrency": zod.string().nullish().describe('ISO 4217 code the consolidated financial reports default to (e.g. \"GBP\"). Empty\/absent ⇒ the FX table\'s base currency is used. Display-only — amounts are converted at view time via the broker FX rates; nothing is re-stored.'),
  "oidcIssuerUrl": zod.string().nullish(),
  "deploymentProfile": zod.enum(['enterprise', 'business', 'nonprofit', 'self-hosted', 'demo']).optional().describe('Deployment context chosen in the setup wizard, which relaxes enterprise couplings by choice (e.g. a charity\/self-hosted instance on a plain-HTTP LAN). Optional; absent until an admin selects one. The infra-level DEPLOYMENT_PROFILE env var takes precedence on a fresh boot (see docs\/REVERSE-PROXY.md).'),
  "loggingSync": zod.object({
  "enabled": zod.boolean(),
  "url": zod.string().nullish(),
  "acknowledgedWarranty": zod.boolean().describe('The admin acknowledged egressed data is outside OmniProject\'s warranty.')
}).optional().describe('Opt-in state-history egress to an operator-owned logging server (off by default). The single deliberate relaxation of OmniProject\'s stateless posture; egressed data is the operator\'s responsibility and outside OmniProject\'s warranty. Enabling it unlocks historical time-travel.'),
  "fieldOverrides": zod.object({
  "fields": zod.record(zod.string(), zod.object({
  "surface": zod.boolean(),
  "store": zod.boolean()
}).describe('Whether a field\/entity can be surfaced (read) and stored (written).')).optional(),
  "entities": zod.record(zod.string(), zod.object({
  "surface": zod.boolean(),
  "store": zod.boolean()
}).describe('Whether a field\/entity can be surfaced (read) and stored (written).')).optional()
}).optional().describe('Admin translation-layer overrides for the capability map. Each entry REPLACES that field\'s\/entity\'s surface+store, correcting a mis-mapping.')
})


